#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

bool is_temperature_rising(int current, int previous)
{
    return (current > previous);
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;
    case CONTROLLER_INPUT_INVALID_TEMPERATURE:
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;
    case CONTROLLER_INPUT_NONE:
        // Handle stale sensor data by checking timeout
        if (controller->last_valid_sensor_ms > 0U && 
            (input.now_ms - controller->last_valid_sensor_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
            controller_set_safe_off(controller);
            return output;
        }
        // For None input, treat as malformed and turn off heater
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        break;
    }

    if (!controller->has_valid_sensor) {
        // Malformed input or timeout - turn off heater
        controller->heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
        return output;
    }

    if (input.kind == CONTROLLER_INPUT_NONE) {
        // No valid input - turn off heater
        controller->heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
        return output;
    }

    int temperature_c = input.temperature_c;
    bool rising = is_temperature_rising(temperature_c, controller->last_temperature_c);

    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        // Check for early off condition: 50 <= TEMP <= 52 and rising
        if ((temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) && 
            (temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) && 
            rising) {
            controller->heater_on = false;
            output.state = CONTROLLER_STATE_HOLDING;
            output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
            output.changed = true;
            return output;
        }

        // Check upper band: TEMP > 52, turn off heater
        if (temperature_c > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            controller->heater_on = false;
            output.state = CONTROLLER_STATE_SAFE_OFF;
            output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
            output.changed = true;
            return output;
        }

        // Normal case: 47 <= TEMP < 50, turn on heater
        if (temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
            controller->heater_on = true;
            output.state = CONTROLLER_STATE_HEATING;
            output.state_name = controller_state_name(CONTROLLER_STATE_HEATING);
            output.changed = true;
        } else {
            // 47 <= TEMP < 50, holding state - preserve previous safe actuator state
            if (previous_heater_on) {
                controller->heater_on = true;
                output.state = CONTROLLER_STATE_HOLDING;
                output.state_name = controller_state_name(CONTROLLER_STATE_HOLDING);
                output.changed = true;
            } else {
                controller->heater_on = false;
                output.state = CONTROLLER_STATE_SAFE_OFF;
                output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
                output.changed = true;
            }
        }
    }

    // Default case: turn off heater on any other valid input or when state changes
    if (previous_heater_on != controller->heater_on) {
        controller->heater_on = false;
        output.state = CONTROLLER_STATE_SAFE_OFF;
        output.state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF);
        output.changed = true;
    }

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_OFF:
    default:
        return "STATE SAFE_OFF";
    }
}

